/**
 * Alloy — a blended derivative-free optimizer for small budgets.
 *
 * JS twin of humpday/optimizers/alloy.py (see that module's docstring for
 * provenance: the algorithm was generated by a language model at the
 * equal-weights point of an inspiration simplex over NM, DE, CMA-ES,
 * pattern search and simulated annealing, then validated out of sample).
 *
 * Mechanism: DE-population init; Nelder-Mead simplex of the best members;
 * per step one of four move generators chosen uniformly (NM
 * reflect/expand/contract, DE mutation + crossover, Gaussian perturbation
 * with success-adapted diagonal covariance, Hooke-Jeeves coordinate probe);
 * simulated-annealing acceptance with geometric cooling; reheat-and-rebuild
 * restart on stagnation.
 */

if (typeof module !== 'undefined' && module.exports) {
    const _base = require('./base-optimizer.js');
    globalThis.Optimizer = _base.Optimizer;
    globalThis.MathUtils = _base.MathUtils;
}

class Alloy extends Optimizer {
    constructor(objective, nTrials, nDim) {
        super(objective, nTrials, nDim);
        this.name = 'Alloy';
    }

    optimize() {
        const n = this.nDim;
        const clip = (x) => x.map((v) => (v < 0 ? 0 : v > 1 ? 1 : v));
        const gauss = () => {
            let u = 0, v = 0;
            while (u === 0) u = Math.random();
            while (v === 0) v = Math.random();
            return Math.sqrt(-2.0 * Math.log(u)) * Math.cos(2.0 * Math.PI * v);
        };
        const left = () => this.evaluations < this.nTrials;
        const feval = (x) => this.evaluate(clip(x));

        // ---- init (DE graft): population ----
        const popSize = Math.max(n + 1, Math.min(8 + 2 * n, Math.max(5, Math.floor(this.nTrials / 6))));
        const pop = [], popF = [];
        for (let i = 0; i < popSize && left(); i++) {
            const x = Array(n).fill(0).map(() => Math.random());
            pop.push(x);
            popF.push(feval(x));
        }
        if (pop.length === 0) return { bestValue: this.bestValue, bestX: this.bestX };

        let order = pop.map((_, i) => i).sort((a, b) => popF[a] - popF[b]);
        let simplex = order.slice(0, n + 1).map((i) => pop[i].slice());
        let simplexF = order.slice(0, n + 1).map((i) => popF[i]);
        while (simplex.length < n + 1 && left()) {
            const b = simplex[0].slice();
            const j = (simplex.length - 1) % n;
            b[j] = Math.min(1.0, b[j] + 0.1);
            simplex.push(b);
            simplexF.push(feval(b));
        }

        // ---- adaptation state ----
        let step = 0.25;
        let sigma = 0.2;
        const covDiag = Array(n).fill(0.04);
        const F = 0.6, CR = 0.9;

        // ---- SA temperature ----
        const fLo = Math.min(...simplexF), fHi = Math.max(...simplexF);
        const T0 = Math.max(1e-6, (fHi - fLo) + 1e-3);
        let T = T0;

        const orderSimplex = () => {
            const idx = simplex.map((_, i) => i).sort((a, b) => simplexF[a] - simplexF[b]);
            simplex = idx.map((i) => simplex[i].slice());
            simplexF = idx.map((i) => simplexF[i]);
        };
        const centroidOf = (exclude) => {
            const c = Array(n).fill(0);
            let m = 0;
            for (let i = 0; i < simplex.length; i++) {
                if (i === exclude) continue;
                for (let d = 0; d < n; d++) c[d] += simplex[i][d];
                m++;
            }
            return c.map((v) => v / m);
        };
        const accept = (fNew, fOld) => {
            if (fNew <= fOld) return true;
            if (T <= 1e-12) return false;
            return Math.random() < Math.exp(-(fNew - fOld) / T);
        };

        let stagnation = 0;
        while (left()) {
            orderSimplex();
            const worstI = simplex.length - 1;
            const bestX = simplex[0];
            const worstX = simplex[worstI];
            const worstF = simplexF[worstI];
            const cen = centroidOf(worstI);

            const r = Math.random();
            let improved = false;

            if (r < 0.25) {
                // Nelder-Mead reflect / expand / contract / shrink
                const refl = cen.map((c, d) => c + (c - worstX[d]));
                if (!left()) break;
                const fr = feval(refl);
                let cand = null, cf = null;
                if (fr < simplexF[0]) {
                    const exp = cen.map((c, d) => c + 2.0 * (c - worstX[d]));
                    if (left()) {
                        const fe = feval(exp);
                        if (fe < fr) { cand = exp; cf = fe; } else { cand = refl; cf = fr; }
                    } else { cand = refl; cf = fr; }
                } else if (fr < worstF) {
                    cand = refl; cf = fr;
                } else {
                    const con = cen.map((c, d) => c + 0.5 * (worstX[d] - c));
                    if (left()) {
                        const fc = feval(con);
                        if (fc < worstF) { cand = con; cf = fc; }
                        else {
                            for (let i = 1; i < simplex.length && left(); i++) {
                                simplex[i] = simplex[i].map((v, d) => bestX[d] + 0.5 * (v - bestX[d]));
                                simplexF[i] = feval(simplex[i]);
                            }
                        }
                    }
                }
                if (cand !== null && accept(cf, worstF)) {
                    simplex[worstI] = clip(cand);
                    simplexF[worstI] = cf;
                    if (cf < worstF) improved = true;
                }
            } else if (r < 0.50) {
                // Differential Evolution: rand/1 or current-to-best/1
                const idxs = simplex.map((_, i) => i);
                for (let i = idxs.length - 1; i > 0; i--) {
                    const j = Math.floor(Math.random() * (i + 1));
                    [idxs[i], idxs[j]] = [idxs[j], idxs[i]];
                }
                const a = idxs[0], b = idxs[1 % idxs.length], c = idxs[2 % idxs.length];
                let mutant;
                if (Math.random() < 0.5) {
                    mutant = simplex[a].map((v, d) => v + F * (simplex[b][d] - simplex[c][d]));
                } else {
                    mutant = worstX.map((v, d) =>
                        v + F * (bestX[d] - v) + F * (simplex[b][d] - simplex[c][d]));
                }
                const jr = Math.floor(Math.random() * n);
                const trial = mutant.map((v, d) =>
                    (Math.random() < CR || d === jr) ? v : worstX[d]);
                if (!left()) break;
                const ft = feval(trial);
                if (accept(ft, worstF)) {
                    simplex[worstI] = clip(trial);
                    simplexF[worstI] = ft;
                    if (ft < worstF) improved = true;
                }
            } else if (r < 0.75) {
                // CMA-style Gaussian sampling with adaptive diagonal covariance
                const cand = bestX.map((v, d) => v + sigma * gauss() * Math.sqrt(covDiag[d]));
                if (!left()) break;
                const fc = feval(cand);
                if (accept(fc, worstF)) {
                    if (fc < worstF) {
                        improved = true;
                        for (let d = 0; d < n; d++) {
                            const delta = cand[d] - bestX[d];
                            covDiag[d] = 0.8 * covDiag[d] + 0.2 * (delta * delta + 1e-8);
                        }
                    }
                    simplex[worstI] = clip(cand);
                    simplexF[worstI] = fc;
                }
            } else {
                // pattern search: Hooke-Jeeves coordinate probes
                let cur = bestX.slice();
                let curF = simplexF[0];
                const baseF = curF;
                for (let d = 0; d < n && left(); d++) {
                    let trial = cur.slice();
                    trial[d] += step;
                    let ft = feval(trial);
                    if (ft < curF) { cur = clip(trial); curF = ft; }
                    else {
                        if (!left()) break;
                        trial = cur.slice();
                        trial[d] -= step;
                        ft = feval(trial);
                        if (ft < curF) { cur = clip(trial); curF = ft; }
                    }
                }
                if (curF < baseF) {
                    improved = true;
                    if (accept(curF, worstF)) {
                        simplex[worstI] = cur;
                        simplexF[worstI] = curF;
                    }
                } else {
                    step *= 0.5;
                    if (step < 1e-6) step = 0.25;
                }
            }

            // ---- adaptation of global scales ----
            if (improved) {
                stagnation = 0;
                sigma = Math.min(0.5, sigma * 1.05);
            } else {
                stagnation++;
                sigma = Math.max(1e-3, sigma * 0.97);
            }

            // ---- SA cooling ----
            T *= 0.995;
            if (T < 1e-9) T = 1e-9;

            // ---- SA-driven restart when stuck ----
            if (stagnation > Math.max(12, 4 * n) && left()) {
                stagnation = 0;
                T = Math.max(T0 * 0.5, T * 5.0);
                step = 0.25;
                sigma = 0.2;
                const keep = this.bestX.slice();
                simplex = [keep.slice()];
                simplexF = [this.bestValue];
                for (let i = 0; i < n && left(); i++) {
                    const p = keep.map((v) => Math.min(1.0, Math.max(0.0, v + (Math.random() * 0.6 - 0.3))));
                    simplex.push(p);
                    simplexF.push(feval(p));
                }
                while (simplex.length < n + 1 && left()) {
                    const p = Array(n).fill(0).map(() => Math.random());
                    simplex.push(p);
                    simplexF.push(feval(p));
                }
            }
        }

        return {
            bestValue: this.bestValue,
            bestX: this.bestX,
            evaluations: this.evaluations,
            success: true,
            path: this.trackPath ? this.path : null
        };
    }
}

if (typeof module !== 'undefined' && module.exports) {
    module.exports = { Alloy };
} else {
    window.Alloy = Alloy;
}
